package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_ReturnsCSVPrinter() throws IOException {
        Appendable appendable = new StringBuilder();
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertEquals(appendable, printer.getOut());
    }

    @Test
    void testPrint_WithMockAppendable() throws IOException {
        Appendable mockAppendable = mock(Appendable.class);
        CSVPrinter printer = csvFormat.print(mockAppendable);
        assertNotNull(printer);
        assertEquals(mockAppendable, printer.getOut());
    }

    @Test
    void testPrint_ThrowsIOException() throws IOException {
        Appendable throwingAppendable = new Appendable() {
            @Override
            public Appendable append(CharSequence csq) throws IOException {
                throw new IOException("append error");
            }

            @Override
            public Appendable append(char c) throws IOException {
                throw new IOException("append error");
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) throws IOException {
                throw new IOException("append error");
            }
        };
        // The print method itself does not throw IOException on append, it just returns a CSVPrinter.
        // But CSVPrinter may throw IOException later. So here just call print and assert no exception.
        CSVPrinter printer = csvFormat.print(throwingAppendable);
        assertNotNull(printer);
        assertEquals(throwingAppendable, printer.getOut());
    }

    @Test
    void testPrint_WithDifferentCSVFormat() throws IOException {
        CSVFormat customFormat = CSVFormat.EXCEL.withDelimiter(';').withQuote('\'');
        Appendable appendable = new StringBuilder();
        CSVPrinter printer = customFormat.print(appendable);
        assertNotNull(printer);
        assertEquals(appendable, printer.getOut());
    }
}
